import java.util.ArrayList;

public class Main {
    public static boolean addStudent(ArrayList<String> roster, String name) {
        if (roster.contains(name)) {
            return false;
        }
        roster.add(name);
        return true;
    }

    public static boolean removeStudent(ArrayList<String> roster, String name) {
        return roster.remove(name);
    }

    public static void printRoster(ArrayList<String> roster) {
        System.out.println("Roster (" + roster.size() + " students):");
        for (String name : roster) {
            System.out.println(name);
        }
    }

    public static void main(String[] args) {
        ArrayList<String> roster = new ArrayList<String>();
        System.out.println(addStudent(roster, "Alice"));
        System.out.println(addStudent(roster, "Bob"));
        System.out.println(addStudent(roster, "Charlie"));
        System.out.println(addStudent(roster, "Alice"));
        removeStudent(roster, "Bob");
        printRoster(roster);
    }
}
